const now = new Date();
const monday = new Date(now);
monday.setDate(now.getDate() - now.getDay() + 1);
const sunday = new Date(monday);
sunday.setDate(monday.getDate() + 6);

const fmt = (d) => d.toISOString().split('T')[0];

return [{
  json: {
    start_date: fmt(monday),
    end_date: fmt(sunday),
    current_week: `Semana ${Math.ceil((monday - new Date(monday.getFullYear(), 0, 1)) / 604800000)}`,
    date_range: `${fmt(monday)} al ${fmt(sunday)}`,
    year: monday.getFullYear()
  }
}];

const response = $input.first().json;
const content = response.content[0].text;

// Extraer JSON de la respuesta
let calendar;
try {
  // Buscar JSON en la respuesta
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  calendar = JSON.parse(jsonMatch ? jsonMatch[0] : content);
} catch(e) {
  throw new Error('Error parsing Claude response: ' + e.message + '\nContent: ' + content.substring(0, 500));
}

// Retornar una fila por pieza de contenido
return calendar.pieces.map(piece => ({ json: { ...piece, week: calendar.week } }));
